class Solution {
public:
    bool canTransform(string start, string result) {
        int n = start.size();
        if (n == 0 || start.size() != result.size()) return false;

        for (int i = 0; i < n; ++i) {
            if (start[i] == 'X' && result[i] == 'X') continue;
            if (start[i] == 'L' && result[i] == 'R') return false;
            if (start[i] == 'R' && result[i] == 'L') return false;

            int j = i + 1;
            int leftCnt = 0, rightCnt = 0;
            while (j < n && start[j] == 'X') {
                ++j;
                ++leftCnt;
            }
            while (j < n && result[j] == 'X') {
                ++j;
                ++rightCnt;
            }
            if (j == n) return false;
            if (leftCnt != rightCnt) return false;
            if ((start[i] == 'L' && result[i] == 'L') || (start[i] == 'R' && result[i] == 'R')) {
                if (leftCnt % 2 != 0) return false;
            } else {
                if (leftCnt % 2 == 0) return false;
            }
        }
        return true;
    }
};
